#include<cstdio>
#include<cstring>
#include<algorithm>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(b,c) for(int c=head[(b)];c;c=nxt[c])
namespace jr_zlw
{
	inline int read()
	{
		int res=0;char ch=getchar();bool flag=0;
		while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
		while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
		return flag ? -res : res ;
	}
	template<typename T> inline T min(T x,T y){return x<y?x:y;}
	template<typename T> inline T max(T x,T y){return y>x?x:y;}
	template<typename T> inline void Swap(T &x,T &y){T tmp=x;x=y;y=tmp;}
	template<typename T> inline void rd(T &x)
	{
		x=0;char ch=getchar();bool flag=0;
		while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
		while(ch<='9'&&ch>='0')x=x*10+(ch^48),ch=getchar();
		flag ? x = -x : 0 ;
	}
	const int N=1e5+10;int head[N],des[N<<1],nxt[N<<1],cgt,tot,cnt[N],ans[N],tt[N],L[N],R[N],col[N];
	inline void ins(int x,int y){nxt[++cgt]=head[x];des[head[x]=cgt]=y;}
	inline void dfs(int u,int fa=0){L[u]=++tot;grep(u,i)if(des[i]^fa)dfs(des[i],u);R[u]=tot;}
	struct Sort
	{
		int l,r,k,idx;
		inline bool operator<(const Sort &Q)const{int b1=l>>8,b2=Q.l>>8;return b1^b2?b1<b2:r<Q.r;}
	}Q[N];
	int t[N];const int base=1e5+2;int n;
	inline void add(int p,int v){p=base-p;while(p<=100003)t[p]+=v,p+=(p&-p);return;}
	inline int qry(int p){p=base-p;int v=0;while(p)v+=t[p],p^=(p&-p);return v;}
	inline void ins(int k){add(cnt[k],-1);add(++cnt[k],1);}
	inline void del(int k){add(cnt[k],-1);add(--cnt[k],1);}
	inline void mian()
	{
		rd(n);int qq=read();rep(1,n,i)tt[i]=read();
		rep(2,n,i){int x=read(),y=read();ins(x,y);ins(y,x);}
		dfs(1);rep(1,n,i)col[L[i]]=tt[i];
		rep(1,qq,i){int u=read();Q[i].l=L[u];Q[i].r=R[u];Q[i].k=read();Q[i].idx=i;}
		std::sort(Q+1,Q+qq+1);int L=1,R=0; 
		rep(1,qq,i)
		{
			while(L>Q[i].l)ins(col[--L]);while(R<Q[i].r)ins(col[++R]);
			while(L<Q[i].l)del(col[L++]);while(R>Q[i].r)del(col[R--]);
			ans[Q[i].idx]=qry(Q[i].k);
		}
		rep(1,qq,i)printf("%d\n",ans[i]);puts("");return;
	}
}
int main()
{
	jr_zlw::mian();
	return 0;
}
